// Check if a number is a palindrome
int isPalindrome(int num) {
    int original = num;
    int reversed = 0;
    while (num > 0) {
        reversed = reversed * 10 + num % 10;
        num /= 10;
    }
    return original == reversed;
}

// Check if a number meets the exact count condition
int isValidNumber(int num) {
    int count[10] = {0};
    int temp = num;
    while (temp > 0) {
        int digit = temp % 10;
        if (digit > 0 && digit <= 9) {
            count[digit]++;
        }
        temp /= 10;
    }
    for (int i = 1; i <= 9; i++) {
        if (count[i] != i) {
            return 0;
        }
    }
    return 1;
}

// Generate the next special number
int64_t solve(int64_t n) {
    int64_t candidate = n + 1;
    while (1) {
        if (isPalindrome(candidate) && isValidNumber(candidate)) {
            return candidate;
        }
        candidate++;
    }
}
